// ─── RISK SCORE — LATEST READINGS ONLY ───────────────────────
const input = $input.first().json || {};

// Parse FHIR bundle from all possible wrapper shapes
let bundle = {};
try {
  const raw = input.data ?? input.body ?? input;
  bundle = typeof raw === 'string' ? JSON.parse(raw) : raw;
  if (!bundle.entry && !bundle.resourceType) {
    const inner = bundle.data ?? bundle.body ?? null;
    if (inner) bundle = typeof inner === 'string' ? JSON.parse(inner) : inner;
  }
} catch (err) {
  return [{ json: { html: `<div style='padding:16px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;color:#991b1b'><strong>Could not parse vitals:</strong> ${err.message}</div>` } }];
}

const entries = bundle.entry?.map(e => e.resource) ?? [];

if (!entries.length) {
  return [{ json: { html: `<div style='padding:16px;background:#fefce8;border:1px solid #fde047;border-radius:8px;color:#854d0e'><strong>Risk score unavailable</strong><br>No vital signs found for this patient.</div>` } }];
}

// Deduplicate: keep only the latest per vital type
const latestByType = new Map();
for (const obs of entries) {
  const typeKey = obs.code?.text || obs.code?.coding?.[0]?.display || obs.code?.coding?.[0]?.code || 'unknown';
  const obsDate = new Date(obs.effectiveDateTime || obs.issued || 0);
  const existing = latestByType.get(typeKey);
  if (!existing || obsDate > new Date(existing.effectiveDateTime || existing.issued || 0)) {
    latestByType.set(typeKey, obs);
  }
}

const latest = Array.from(latestByType.values());

let score = 0;
const rows = [];
const fmtDate = (d) => d ? new Date(d).toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric' }) : '—';

for (const obs of latest) {
  const name   = (obs.code?.text || obs.code?.coding?.[0]?.display || 'Unknown vital').trim();
  const date   = fmtDate(obs.effectiveDateTime || obs.issued);
  const val    = obs.valueQuantity?.value;
  const unit   = obs.valueQuantity?.unit || '';
  const nameLo = name.toLowerCase();

  if (val !== undefined && val !== null) {
    let status = 'normal';
    let note   = 'Within expected range';

    if (nameLo.includes('heart rate') || nameLo.includes('pulse')) {
      if (val > 100)       { score += 2; status = 'high';       note = `Tachycardia (>100 bpm)`; }
      else if (val < 60)   { score += 1; status = 'low';        note = `Bradycardia (<60 bpm)`; }
    } else if (nameLo.includes('respiratory') || nameLo.includes('breath')) {
      if (val > 20)        { score += 2; status = 'high';       note = `Elevated respiratory rate (>20/min)`; }
      else if (val < 12)   { score += 1; status = 'low';        note = `Low respiratory rate (<12/min)`; }
    } else if (nameLo.includes('temperature') || nameLo.includes('body temp')) {
      if (val > 38.3)      { score += 2; status = 'high';       note = `Fever (${val.toFixed(1)}°C)`; }
      else if (val < 36.0) { score += 1; status = 'low';        note = `Hypothermia (${val.toFixed(1)}°C)`; }
    } else if (nameLo.includes('oxygen') || nameLo.includes('spo2') || nameLo.includes('saturation')) {
      if (val < 94)        { score += 3; status = 'critical';   note = `Low O₂ saturation (<94%)`; }
      else if (val < 96)   { score += 1; status = 'borderline'; note = `Borderline O₂ saturation`; }
    } else if (nameLo.includes('pain')) {
      if (val >= 7)        { score += 2; status = 'high';       note = `Severe pain (${val}/10)`; }
      else if (val >= 4)   { score += 1; status = 'borderline'; note = `Moderate pain (${val}/10)`; }
    } else if (nameLo.includes('bmi') || nameLo.includes('body mass index')) {
      if (val >= 35)       { score += 1; status = 'borderline'; note = `Obese class II+ (BMI ${val.toFixed(1)})`; }
      else if (val < 18.5) { score += 1; status = 'low';        note = `Underweight (BMI ${val.toFixed(1)})`; }
    } else if (nameLo.includes('glucose') || nameLo.includes('blood glucose')) {
      if (val > 200)       { score += 2; status = 'high';       note = `High glucose (${val.toFixed(0)} mg/dL)`; }
      else if (val < 70)   { score += 2; status = 'low';        note = `Low glucose (${val.toFixed(0)} mg/dL)`; }
    }

    rows.push({ vital: name, value: `${val.toFixed(1)} ${unit}`.trim(), date, status, note });
  }

  if (Array.isArray(obs.component)) {
    let sys = null; let dia = null;
    for (const comp of obs.component) {
      const cn = (comp.code?.text || comp.code?.coding?.[0]?.display || '').toLowerCase();
      const cv = comp.valueQuantity?.value;
      if (cv == null) continue;
      if (cn.includes('systolic'))  sys = cv;
      if (cn.includes('diastolic')) dia = cv;
    }
    if (sys !== null || dia !== null) {
      let status = 'normal'; let note = 'BP within normal range'; let bpScore = 0;
      const bpStr = `${sys !== null ? sys.toFixed(0) : '?'}/${dia !== null ? dia.toFixed(0) : '?'} mmHg`;
      if (sys !== null) {
        if (sys >= 180)      { bpScore += 3; status = 'critical';   note = `Hypertensive crisis (systolic ${sys} mmHg)`; }
        else if (sys >= 140) { bpScore += 2; status = 'high';       note = `Stage 2 hypertension (systolic ${sys} mmHg)`; }
        else if (sys >= 130) { bpScore += 1; status = 'borderline'; note = `Stage 1 hypertension (systolic ${sys} mmHg)`; }
        else if (sys < 90)   { bpScore += 2; status = 'low';        note = `Hypotension (systolic ${sys} mmHg)`; }
      }
      if (dia !== null && bpScore === 0) {
        if (dia >= 90)       { bpScore += 1; status = 'high';       note = `Elevated diastolic (${dia} mmHg)`; }
        else if (dia < 60)   { bpScore += 1; status = 'low';        note = `Low diastolic (${dia} mmHg)`; }
      }
      score += bpScore;
      rows.push({ vital: 'Blood Pressure', value: bpStr, date, status, note });
    }
  }
}

const riskLevel  = score >= 6 ? 'critical' : score >= 4 ? 'high' : score >= 2 ? 'moderate' : 'low';
const riskLabels = { critical: '🔴 Critical', high: '🟠 High', moderate: '🟡 Moderate', low: '🟢 Low' };
const riskColors = { critical: '#dc2626', high: '#ea580c', moderate: '#ca8a04', low: '#16a34a' };
const riskBg     = { critical: '#fef2f2', high: '#fff7ed', moderate: '#fefce8', low: '#f0fdf4' };

const statusBadge = (s) => {
  const map = { critical:'#dc2626', high:'#ea580c', borderline:'#ca8a04', normal:'#16a34a', low:'#2563eb' };
  const color = map[s] || '#6b7280';
  return `<span style="background:${color}20;color:${color};border:1px solid ${color}40;border-radius:4px;padding:1px 7px;font-size:11px;font-weight:600;text-transform:uppercase">${s}</span>`;
};

const tableRows = rows.map(r => `
  <tr style="border-bottom:1px solid #f0f0f0">
    <td style="padding:7px 10px;font-weight:500">${r.vital}</td>
    <td style="padding:7px 10px;font-family:monospace;font-size:13px">${r.value}</td>
    <td style="padding:7px 10px;color:#6b7280;font-size:12px">${r.date}</td>
    <td style="padding:7px 10px">${statusBadge(r.status)}</td>
    <td style="padding:7px 10px;color:#374151;font-size:12px">${r.note}</td>
  </tr>`).join('');

const html = `
<div style="font-family:system-ui,sans-serif">
  <div style="background:${riskBg[riskLevel]};border:2px solid ${riskColors[riskLevel]};border-radius:10px;padding:16px 20px;margin-bottom:18px;display:flex;align-items:center;gap:18px">
    <div style="font-size:36px;font-weight:800;color:${riskColors[riskLevel]}">${score}</div>
    <div>
      <div style="font-size:18px;font-weight:700;color:${riskColors[riskLevel]}">${riskLabels[riskLevel]} Risk</div>
      <div style="font-size:12px;color:#6b7280;margin-top:2px">Composite score from latest vitals only · ${rows.length} vital type(s) assessed</div>
    </div>
  </div>
  <div style="border:1px solid #e5e7eb;border-radius:8px;overflow:hidden">
    <table style="width:100%;border-collapse:collapse">
      <thead>
        <tr style="background:#f9fafb">
          <th style="padding:9px 10px;text-align:left;font-size:12px;color:#6b7280;font-weight:600">VITAL SIGN</th>
          <th style="padding:9px 10px;text-align:left;font-size:12px;color:#6b7280;font-weight:600">LATEST VALUE</th>
          <th style="padding:9px 10px;text-align:left;font-size:12px;color:#6b7280;font-weight:600">DATE</th>
          <th style="padding:9px 10px;text-align:left;font-size:12px;color:#6b7280;font-weight:600">STATUS</th>
          <th style="padding:9px 10px;text-align:left;font-size:12px;color:#6b7280;font-weight:600">CLINICAL NOTE</th>
        </tr>
      </thead>
      <tbody>${tableRows || '<tr><td colspan="5" style="padding:14px;color:#9ca3af;text-align:center">No scoreable vitals found</td></tr>'}</tbody>
    </table>
  </div>
  <div style="font-size:11px;color:#9ca3af;margin-top:10px;text-align:right">Score legend: O₂ sat critical=+3 · BP crisis=+3 · HR/RR/Temp abnormal=+2 · BMI/Pain/others=+1</div>
</div>`;

return [{ json: { html } }];

// ─── CARE GAPS — ENRICHED HTML OUTPUT ────────────────────────
// Reads immunization bundle from node 0, lab bundle from node 1
// Emits { html } with detailed gap analysis table + recommendations.

const allInputs = $input.all();
const immInput  = allInputs[0]?.json || {};
const labInput  = allInputs[1]?.json || {};

// Parse bundles
const parseBundle = (raw) => {
  try { return (typeof raw.data === 'string' ? JSON.parse(raw.data) : raw.data || raw); }
  catch { return {}; }
};

const immBundle = parseBundle(immInput);
const labBundle = parseBundle(labInput);

const imms = immBundle.entry?.map(e => e.resource) ?? [];
const labs = labBundle.entry?.map(e => e.resource) ?? [];

const fmtDate = (d) => d ? new Date(d).toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric' }) : null;

// ── Immunization helpers ──────────────────────────────────────
const immTexts = imms.flatMap(i => [
  i.vaccineCode?.text || '',
  ...(i.vaccineCode?.coding?.map(c => c.display || c.code || '') || [])
]).map(s => s.toLowerCase().trim()).filter(Boolean);

const findImm = (keywords) => {
  for (const imm of imms) {
    const texts = [
      imm.vaccineCode?.text || '',
      ...(imm.vaccineCode?.coding?.map(c => c.display || '') || [])
    ].map(s => s.toLowerCase());
    if (texts.some(t => keywords.some(k => t.includes(k)))) {
      return fmtDate(imm.occurrenceDateTime || imm.recorded);
    }
  }
  return null;
};

// ── Lab helpers ───────────────────────────────────────────────
const findLab = (keywords) => {
  for (const ob of labs) {
    const name = (ob.code?.text || ob.code?.coding?.[0]?.display || '').toLowerCase();
    if (keywords.some(k => name.includes(k))) {
      const val  = ob.valueQuantity ? `${ob.valueQuantity.value?.toFixed(1)} ${ob.valueQuantity.unit || ''}`.trim() : ob.valueString || '—';
      const date = fmtDate(ob.effectiveDateTime || ob.issued);
      return { val, date };
    }
  }
  return null;
};

// ── Screening catalogue ───────────────────────────────────────
const screenings = [
  {
    category: 'Immunizations',
    items: [
      { name:'Influenza (annual)',      keywords:['influenza','flu'],         type:'imm', frequency:'Annually',    priority:'routine' },
      { name:'Pneumococcal (PCV)',      keywords:['pneumococcal','pcv','pneumo'], type:'imm', frequency:'Age-based', priority:'routine' },
      { name:'Tdap / DTaP',            keywords:['tdap','dtap'],             type:'imm', frequency:'Every 10 yrs', priority:'routine' },
      { name:'COVID-19',               keywords:['covid'],                   type:'imm', frequency:'Per guidelines', priority:'routine' },
      { name:'Hepatitis B',            keywords:['hepatitis b','hep b'],     type:'imm', frequency:'3-dose series', priority:'routine' },
      { name:'Hepatitis A',            keywords:['hepatitis a','hep a'],     type:'imm', frequency:'2-dose series', priority:'routine' },
      { name:'Zoster (Shingrix)',       keywords:['zoster','shingrix','varicella zoster'], type:'imm', frequency:'2-dose (age 50+)', priority:'routine' },
      { name:'MMR',                    keywords:['mmr','measles','mumps'],   type:'imm', frequency:'2 doses',       priority:'routine' },
    ]
  },
  {
    category: 'Lab Screenings',
    items: [
      { name:'Hemoglobin A1c',         keywords:['hemoglobin a1c','hba1c','a1c'], type:'lab', frequency:'Annually (diabetics)', priority:'important' },
      { name:'Lipid Panel',            keywords:['lipid','cholesterol','ldl','hdl'], type:'lab', frequency:'Every 5 yrs',   priority:'important' },
      { name:'Complete Blood Count',   keywords:['cbc','complete blood count','hemoglobin'], type:'lab', frequency:'Annual',    priority:'routine' },
      { name:'Comprehensive Metabolic',keywords:['comprehensive metabolic','cmp','basic metabolic','bmp'], type:'lab', frequency:'Annual', priority:'routine' },
      { name:'TSH (Thyroid)',          keywords:['tsh','thyroid stimulating'], type:'lab', frequency:'Every 5 yrs',   priority:'routine' },
    ]
  }
];

// ── Build rows ────────────────────────────────────────────────
const priorityIcon = { important: '🔶', routine: '🔷' };

let totalItems = 0; let gapCount = 0;
let sectionHTMLs = [];

for (const section of screenings) {
  const rows = [];
  for (const item of section.items) {
    totalItems++;
    let lastDate = null; let lastValue = '—'; let status;

    if (item.type === 'imm') {
      lastDate = findImm(item.keywords);
      lastValue = lastDate ? '✓ Immunized' : '—';
    } else {
      const found = findLab(item.keywords);
      if (found) { lastDate = found.date; lastValue = found.val; }
    }

    if (lastDate) {
      status = { color: '#16a34a', bg: '#f0fdf4', badge: '✓ On Record', action: 'No action needed' };
    } else {
      gapCount++;
      const p = item.priority;
      status = p === 'important'
        ? { color: '#ea580c', bg: '#fff7ed', badge: '⚠ Gap — Important', action: 'Schedule soon' }
        : { color: '#ca8a04', bg: '#fefce8', badge: '○ Not on Record',   action: 'Review eligibility' };
    }

    rows.push(`
    <tr style="border-bottom:1px solid #f0f0f0">
      <td style="padding:8px 10px">
        <span style="font-size:13px">${priorityIcon[item.priority] || ''}</span>
        <span style="font-weight:500;margin-left:4px">${item.name}</span>
      </td>
      <td style="padding:8px 10px;color:#6b7280;font-size:12px">${item.frequency}</td>
      <td style="padding:8px 10px;color:#374151;font-size:13px;font-family:monospace">${lastValue}</td>
      <td style="padding:8px 10px;color:#6b7280;font-size:12px">${lastDate || '—'}</td>
      <td style="padding:8px 10px">
        <span style="background:${status.bg};color:${status.color};border:1px solid ${status.color}40;border-radius:4px;padding:2px 8px;font-size:11px;font-weight:600;white-space:nowrap">
          ${status.badge}
        </span>
      </td>
      <td style="padding:8px 10px;color:#374151;font-size:12px">${status.action}</td>
    </tr>`);
  }

  sectionHTMLs.push(`
    <div style="margin-bottom:20px">
      <div style="font-size:13px;font-weight:700;color:#374151;padding:8px 10px;background:#f9fafb;border-radius:6px 6px 0 0;border:1px solid #e5e7eb;border-bottom:none">
        ${section.category}
      </div>
      <div style="border:1px solid #e5e7eb;border-radius:0 0 8px 8px;overflow:hidden">
        <table style="width:100%;border-collapse:collapse">
          <thead>
            <tr style="background:#f9fafb;border-bottom:1px solid #e5e7eb">
              <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:600">SCREENING</th>
              <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:600">FREQUENCY</th>
              <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:600">LAST VALUE</th>
              <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:600">LAST DATE</th>
              <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:600">STATUS</th>
              <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280;font-weight:600">ACTION</th>
            </tr>
          </thead>
          <tbody>${rows.join('')}</tbody>
        </table>
      </div>
    </div>`);
}

// ── Summary bar ──────────────────────────────────────���────────
const pct = Math.round(((totalItems - gapCount) / totalItems) * 100);
const summaryColor = gapCount === 0 ? '#16a34a' : gapCount <= 3 ? '#ca8a04' : '#dc2626';

const html = `
<div style="font-family:system-ui,sans-serif">
  <!-- Summary -->
  <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;padding:14px 18px;margin-bottom:20px;display:flex;align-items:center;justify-content:space-between">
    <div>
      <div style="font-size:16px;font-weight:700;color:#1e293b">Preventive Care Summary</div>
      <div style="font-size:12px;color:#64748b;margin-top:2px">${totalItems - gapCount} of ${totalItems} screenings on record · ${gapCount} potential gap(s)</div>
    </div>
    <div style="text-align:center">
      <div style="font-size:28px;font-weight:800;color:${summaryColor}">${pct}%</div>
      <div style="font-size:11px;color:#94a3b8">Up to date</div>
    </div>
  </div>
  ${sectionHTMLs.join('')}
  <div style="font-size:11px;color:#9ca3af;margin-top:6px">🔶 Important gap &nbsp;·&nbsp; 🔷 Routine gap &nbsp;·&nbsp; Based on immunization and lab records in FHIR</div>
</div>`;

return [{ json: { html } }];

// ─── DISCHARGE SUMMARY — ASSEMBLE FHIR CONTEXT ─────────────
// Explicitly fetch from each named node to ensure data is captured

const parseB = (nodeName) => {
  try {
    const raw = $(nodeName).first()?.json;
    // Handle n8n's "data" string wrapper or standard "body"
    const target = raw?.data || raw?.body || raw;
    return (typeof target === 'string' ? JSON.parse(target) : target || {});
  } catch (e) { return {}; }
};

// Map each variable to its specific node name from your JSON
const patient   = parseB('DS: Fetch Patient');
const condB     = parseB('DS: Fetch Conditions');
const medB      = parseB('DS: Fetch Medications');
const vitalB    = parseB('DS: Fetch Vitals');
const labB      = parseB('DS: Fetch Labs');
const allergyB  = parseB('DS: Fetch Allergies');
const encB      = parseB('DS: Fetch Encounters');

const fmtDate = (d) => d ? new Date(d).toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric' }) : '—';
const getName  = (p) => { 
  const n = p?.name?.[0]; 
  return n ? [n.family, ...(n.given||[])].filter(Boolean).join(', ') : 'Unknown'; 
};
const getAge   = (bd) => { 
  if (!bd) return '?'; 
  const t=new Date(); const d=new Date(bd); 
  let a=t.getFullYear()-d.getFullYear(); 
  if(t.getMonth()-d.getMonth()<0||(t.getMonth()-d.getMonth()===0&&t.getDate()<d.getDate()))a--; 
  return a; 
};
const getObs   = (obs) => obs.valueQuantity ? `${obs.valueQuantity.value?.toFixed(1)} ${obs.valueQuantity.unit||''}`.trim() : (obs.valueString||'—');

const conditions  = (condB.entry||[]).map(e => e.resource).map(c => `${c.code?.text||c.code?.coding?.[0]?.display||'?'} (${c.clinicalStatus?.coding?.[0]?.code||'?'})`);
const medications = (medB.entry||[]).map(e => e.resource).map(m => `${m.medicationCodeableConcept?.text||m.medicationCodeableConcept?.coding?.[0]?.display||'?'} — ${m.status||'?'}`);
const vitals      = (vitalB.entry||[]).slice(0,10).map(e => e.resource).map(v => `${v.code?.text||'?'}: ${getObs(v)} (${fmtDate(v.effectiveDateTime)})`);
const labs        = (labB.entry||[]).slice(0,10).map(e => e.resource).map(l => `${l.code?.text||l.code?.coding?.[0]?.display||'?'}: ${getObs(l)} (${fmtDate(l.effectiveDateTime||l.issued)})`);
const allergies   = (allergyB.entry||[]).map(e => e.resource).map(a => `${a.code?.text||a.code?.coding?.[0]?.display||'?'} (${a.criticality||'—'})`);
const encounters  = (encB.entry||[]).map(e => e.resource).map(enc => `${enc.type?.[0]?.text||enc.class?.display||'Encounter'} on ${fmtDate(enc.period?.start)} — ${enc.status||'?'}`);

const patientInfo = `Name: ${getName(patient)} | DOB: ${patient.birthDate||'?'} | Age: ${getAge(patient.birthDate)} | Gender: ${patient.gender||'?'} | MRN: ${patient.id||'?'}`;

const context = [
  `PATIENT: ${patientInfo}`,
  `\nACTIVE CONDITIONS (${conditions.length}):\n${conditions.join('\n') || 'None recorded'}`,
  `\nMEDICATIONS (${medications.length}):\n${medications.join('\n') || 'None recorded'}`,
  `\nALLERGIES (${allergies.length}):\n${allergies.join('\n') || 'NKDA'}`,
  `\nRECENT VITALS:\n${vitals.join('\n') || 'None recorded'}`,
  `\nRECENT LAB RESULTS:\n${labs.join('\n') || 'None recorded'}`,
  `\nRECENT ENCOUNTERS:\n${encounters.join('\n') || 'None recorded'}`,
].join('\n');

return [{ json: { context, patientName: getName(patient) } }];

// ─── FORMAT DISCHARGE SUMMARY HTML ──────────────────────────
const input = $input.first().json;
let text = '';

try {
  // AI Agent returns output in .output field
  text = input.output || '';
} catch { text = ''; }

if (!text) {
  return [{ json: { html: `<div style='padding:16px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;color:#991b1b'><strong>AI Agent error:</strong> No response received. Check that OpenAI credentials are configured.</div>` } }];
}

// Convert markdown-style sections to HTML
const lines = text.split('\n');
let html = '<div style="font-family:system-ui,sans-serif;line-height:1.6">';
html += `<div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:12px 16px;margin-bottom:16px;font-size:13px;color:#1e40af">📄 AI-generated discharge summary based on FHIR patient record. Review before clinical use.</div>`;

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) { html += '<br>'; continue; }
  // Section headers (ALL CAPS or bold-style)
  if (/^[A-Z][A-Z \/(\-]{4,}:?$/.test(trimmed) || trimmed.startsWith('**') && trimmed.endsWith('**')) {
    const label = trimmed.replace(/^\*\*|\*\*$/g,'').replace(/:$/,'');
    html += `<div style="margin-top:16px;margin-bottom:6px;font-size:13px;font-weight:700;color:#1e40af;text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid #e0e7ff;padding-bottom:4px">${label}</div>`;
  } else if (trimmed.startsWith('- ') || trimmed.startsWith('• ')) {
    html += `<div style="padding:3px 0 3px 14px;border-left:3px solid #dbeafe;margin:2px 0;font-size:13px;color:#1e293b">${trimmed.substring(2)}</div>`;
  } else {
    html += `<p style="margin:4px 0;font-size:13px;color:#1e293b">${trimmed}</p>`;
  }
}
html += '</div>';

return [{ json: { html } }];

// ─── PREVISIT SUMMARY — ASSEMBLE FHIR CONTEXT ───────────────

const parseJsonSafe = (value) => {
  if (value == null) return {};
  if (typeof value === 'string') {
    try { return JSON.parse(value); } catch { return {}; }
  }
  return value;
};

const parseFHIRFromNode = (nodeName) => {
  try {
    const raw = $(nodeName).first()?.json ?? {};
    if (raw?.data !== undefined) return parseJsonSafe(raw.data);
    if (raw?.body !== undefined) return parseJsonSafe(raw.body);
    if (raw?.resourceType || raw?.entry) return raw;
    return parseJsonSafe(raw);
  } catch (e) { return {}; }
};

const getResources = (bundle) =>
  Array.isArray(bundle?.entry)
    ? bundle.entry.map(e => e.resource).filter(Boolean)
    : [];

const fmtDate = (d) => {
  if (!d) return '—';
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? '—' : dt.toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric' });
};

const getName = (p) => {
  const n = p?.name?.[0];
  if (!n) return 'Unknown';
  return [...(n.given || []), n.family].filter(Boolean).join(' ');
};

const getAge = (birthDate) => {
  if (!birthDate) return '?';
  const dob = new Date(birthDate);
  if (isNaN(dob.getTime())) return '?';
  const today = new Date();
  let age = today.getFullYear() - dob.getFullYear();
  const m = today.getMonth() - dob.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < dob.getDate())) age--;
  return age;
};

const getCodeText = (r) =>
  r?.code?.text || r?.code?.coding?.[0]?.display || r?.code?.coding?.[0]?.code || '?';

const getMedicationText = (m) =>
  m?.medicationCodeableConcept?.text ||
  m?.medicationCodeableConcept?.coding?.[0]?.display ||
  m?.medication?.concept?.text || '?';

const getAllergyText = (a) =>
  a?.code?.text || a?.code?.coding?.[0]?.display || 'Unknown allergy';

const getImmunizationText = (i) =>
  i?.vaccineCode?.text || i?.vaccineCode?.coding?.[0]?.display || '?';

const getObsValue = (obs) => {
  if (obs?.valueQuantity?.value !== undefined)
    return `${Number(obs.valueQuantity.value).toFixed(1)} ${obs.valueQuantity.unit || ''}`.trim();
  if (obs?.valueString) return obs.valueString;
  if (obs?.valueCodeableConcept?.text) return obs.valueCodeableConcept.text;
  if (Array.isArray(obs?.component)) {
    let sys = null, dia = null;
    for (const c of obs.component) {
      const label = (c?.code?.text || c?.code?.coding?.[0]?.display || '').toLowerCase();
      const val = c?.valueQuantity?.value;
      const unit = c?.valueQuantity?.unit || 'mm[Hg]';
      if (label.includes('systolic')) sys = `${Math.round(val)} ${unit}`;
      if (label.includes('diastolic')) dia = `${Math.round(val)} ${unit}`;
    }
    if (sys || dia) return `${sys ? 'Sys ' + sys : ''}${sys && dia ? ' / ' : ''}${dia ? 'Dia ' + dia : ''}`;
  }
  return '—';
};

const patient    = parseFHIRFromNode('PV: Fetch Patient');
const condB      = parseFHIRFromNode('PV: Fetch Conditions');
const medB       = parseFHIRFromNode('PV: Fetch Medications');
const vitalB     = parseFHIRFromNode('PV: Fetch Vitals');
const labB       = parseFHIRFromNode('PV: Fetch Labs');
const allergyB   = parseFHIRFromNode('PV: Fetch Allergies');
const immB       = parseFHIRFromNode('PV: Fetch Immunizations');

const conditionsRaw    = getResources(condB);
const medicationsRaw   = getResources(medB);
const vitalsRaw        = getResources(vitalB);
const labsRaw          = getResources(labB);
const allergiesRaw     = getResources(allergyB);
const immunizationsRaw = getResources(immB);

// No status filtering — include all, label inline
const conditions = conditionsRaw.map(c =>
  `${getCodeText(c)} (${c?.clinicalStatus?.coding?.[0]?.code || c?.clinicalStatus?.text || 'active'})`
);

const medications = medicationsRaw.map(m => {
  const d = m?.dosageInstruction?.[0];
  const doseVal = d?.doseAndRate?.[0]?.doseQuantity?.value;
  const doseUnit = d?.doseAndRate?.[0]?.doseQuantity?.unit || '';
  const dose = d?.text || (doseVal != null ? `${doseVal} ${doseUnit}`.trim() : 'as directed');
  const asNeeded = d?.asNeededBoolean ? ' as needed' : '';
  return `${getMedicationText(m)} — ${dose}${asNeeded}`;
});

const vitals = vitalsRaw.slice(0, 8).map(v =>
  `${getCodeText(v)}: ${getObsValue(v)} (${fmtDate(v.effectiveDateTime || v.issued)})`
);

const labs = labsRaw.slice(0, 8).map(l =>
  `${getCodeText(l)}: ${getObsValue(l)} (${fmtDate(l.effectiveDateTime || l.issued)})`
);

const allergies = allergiesRaw.map(a =>
  `${getAllergyText(a)} (${a?.criticality || a?.reaction?.[0]?.severity || '—'})`
);

const imms = immunizationsRaw.map(i =>
  `${getImmunizationText(i)} on ${fmtDate(i.occurrenceDateTime || i.recorded)}`
);

const patientInfo = `Name: ${getName(patient)} | DOB: ${patient?.birthDate || '?'} | Age: ${getAge(patient?.birthDate)} | Gender: ${patient?.gender || '?'} | MRN: ${patient?.id || '?'}`;

const context = [
  `PATIENT: ${patientInfo}`,
  `\nACTIVE CONDITIONS (${conditions.length}):\n${conditions.join('\n') || 'None recorded'}`,
  `\nACTIVE MEDICATIONS (${medications.length}):\n${medications.join('\n') || 'None recorded'}`,
  `\nALLERGIES:\n${allergies.join('\n') || 'NKDA'}`,
  `\nRECENT VITALS:\n${vitals.join('\n') || 'None recorded'}`,
  `\nRECENT LABS:\n${labs.join('\n') || 'None recorded'}`,
  `\nIMMUNIZATIONS:\n${imms.join('\n') || 'None recorded'}`,
].join('\n');

return [{
  json: {
    context,
    patientName: getName(patient),
    debug: {
      patientResourceType: patient?.resourceType || null,
      conditionsCountRaw: conditionsRaw.length,
      medicationsCountRaw: medicationsRaw.length,
      vitalsCountRaw: vitalsRaw.length,
      labsCountRaw: labsRaw.length,
      allergiesCountRaw: allergiesRaw.length,
      immunizationsCountRaw: immunizationsRaw.length,
    }
  }
}];

// ─── FORMAT PRE-VISIT SUMMARY HTML ──────────────────────────
const input = $input.first().json;
let text = '';

try {
  const output = input.output;
  if (typeof output === 'string') {
    text = output;
  } else if (Array.isArray(output)) {
    for (const msg of output) {
      if (Array.isArray(msg?.content)) {
        for (const block of msg.content) {
          if (block?.type === 'output_text' && block?.text) text += block.text;
        }
      } else if (typeof msg?.text === 'string') {
        text += msg.text;
      }
    }
  } else if (typeof output === 'object' && output !== null) {
    if (Array.isArray(output?.content)) {
      for (const block of output.content) {
        if (block?.type === 'output_text' && block?.text) text += block.text;
      }
    } else if (typeof output?.text === 'string') {
      text = output.text;
    }
  }
  if (!text) text = input.text || input.message || input.content || '';
} catch (e) { text = ''; }

if (!text) {
  return [{ json: { html: `<div style='padding:16px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;color:#991b1b'><strong>AI Agent error:</strong> No response received. Check that OpenAI credentials are configured.</div>` } }];
}

const lines = text.split('\n');
let html = '<div style="font-family:system-ui,sans-serif;line-height:1.6">';
html += `<div style="background:#f0fdf4;border:1px solid #86efac;border-radius:8px;padding:12px 16px;margin-bottom:16px;font-size:13px;color:#166534">🩺 AI-generated pre-visit brief based on FHIR patient record. Review before seeing patient.</div>`;

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) { html += '<br>'; continue; }
  if (/^[A-Z][A-Z \/(\\-]{4,}:?$/.test(trimmed) || (trimmed.startsWith('**') && trimmed.endsWith('**'))) {
    const label = trimmed.replace(/^\*\*|\*\*$/g,'').replace(/:$/,'');
    html += `<div style="margin-top:16px;margin-bottom:6px;font-size:13px;font-weight:700;color:#166534;text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid #dcfce7;padding-bottom:4px">${label}</div>`;
  } else if (trimmed.startsWith('- ') || trimmed.startsWith('• ') || /^\d+\./.test(trimmed)) {
    const item = trimmed.replace(/^[-•]\s+/,'').replace(/^\d+\.\s*/,'');
    html += `<div style="padding:3px 0 3px 14px;border-left:3px solid #bbf7d0;margin:2px 0;font-size:13px;color:#1e293b">${item}</div>`;
  } else {
    html += `<p style="margin:4px 0;font-size:13px;color:#1e293b">${trimmed}</p>`;
  }
}
html += '</div>';
return [{ json: { html } }];

// ─── PDF REPORT UPLOAD — Decode & prepare payload ────────────────────────────
const body = $input.first().json.body || $input.first().json;

const patientId   = body.patientId   || '';
const fhirBase    = body.fhirBase    || 'http://r4:8080/hapi-fhir-jpaserver/fhir';
const pdfBase64   = body.pdfBase64   || '';
const filename    = body.filename    || 'report.pdf';
const reportType  = body.reportType  || 'labs';
const keepPrev    = body.keepPrevious !== false;
const patientName = body.patientName || '';

if (!patientId) throw new Error('patientId is required');
if (!pdfBase64) throw new Error('pdfBase64 is required');

// Decode base64 → text (best-effort for text-based PDFs)
let pdfText = '';
try {
  pdfText = Buffer.from(pdfBase64, 'base64').toString('utf-8')
    .replace(/[^\x20-\x7E\n\r\t]/g, ' ')
    .replace(/\s{3,}/g, '  ')   // collapse excess whitespace
    .trim()
    .substring(0, 5000);         // hard cap — avoids token overflow in AI node
} catch(e) {
  pdfText = '(could not decode PDF text)';
}

return [{ json: { patientId, fhirBase, pdfText, filename, reportType, keepPrev, patientName } }];

