// ─── PDF REPORT UPLOAD — Build FHIR Resources ────────────────────────────────
const aiInput    = $input.first().json;
const prev       = $('PR: Decode PDF').first().json;
const patientId  = prev.patientId;
const fhirBase   = prev.fhirBase;
const reportType = prev.reportType;

// ── Extract raw text from ANY response shape ──────────────────────────────────
function extractRawText(inp) {
  // Shape 1: output[0].content[0].text  (Anthropic Messages API)
  if (Array.isArray(inp.output)) {
    for (const msg of inp.output) {
      if (Array.isArray(msg.content)) {
        for (const block of msg.content) {
          if (block.text) return block.text;
        }
      }
      if (typeof msg.text === 'string') return msg.text;
    }
  }
  // Shape 2: message.content  (OpenAI chat node)
  if (inp.message?.content) return inp.message.content;
  // Shape 3: choices[0].message.content  (raw OpenAI API)
  if (Array.isArray(inp.choices) && inp.choices[0]?.message?.content)
    return inp.choices[0].message.content;
  // Shape 4: top-level text / content / output
  if (typeof inp.text    === 'string') return inp.text;
  if (typeof inp.content === 'string') return inp.content;
  if (typeof inp.output  === 'string') return inp.output;
  // Fallback: stringify and try regex scrape below
  return JSON.stringify(inp);
}

// ── Robust JSON parser with 4 fallback strategies ─────────────────────────────
function safeParseAI(raw) {
  if (!raw) return null;
  let txt = raw.replace(/```json|```/gi, '').trim();

  // Attempt 1: straight parse
  try { return JSON.parse(txt); } catch(_) {}

  // Attempt 2: extract between first { and last }
  const start = txt.indexOf('{');
  const end   = txt.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    try { return JSON.parse(txt.substring(start, end + 1)); } catch(_) {}
  }

  // Attempt 3: salvage extracted[] array from truncated JSON
  const arrStart = txt.indexOf('"extracted"');
  if (arrStart !== -1) {
    const bracketOpen = txt.indexOf('[', arrStart);
    if (bracketOpen !== -1) {
      let depth = 0; let i = bracketOpen; let lastGoodClose = bracketOpen;
      while (i < txt.length) {
        if (txt[i] === '[' || txt[i] === '{') depth++;
        if (txt[i] === ']' || txt[i] === '}') { depth--; if (depth === 1) lastGoodClose = i; }
        i++;
      }
      try {
        const items = JSON.parse(txt.substring(bracketOpen, lastGoodClose + 1));
        const rdMatch  = txt.match(/"reportDate"\s*:\s*"([^"]+)"/);
        const sumMatch = txt.match(/"summary"\s*:\s*"([^"]+)"/);
        return {
          reportDate: rdMatch  ? rdMatch[1]  : new Date().toISOString().split('T')[0],
          summary:    sumMatch ? sumMatch[1] : 'Partial extraction (response truncated)',
          extracted:  items
        };
      } catch(_) {}
    }
  }

  // Attempt 4: regex-scrape individual items
  const itemRx = /\{\s*"name"\s*:\s*"([^"]+)"\s*,\s*"value"\s*:\s*([\d.]+)\s*,\s*"unit"\s*:\s*"([^"]*)"\s*,\s*"date"\s*:\s*"([^"]+)"/g;
  const items = []; let m;
  while ((m = itemRx.exec(txt)) !== null) {
    items.push({ name: m[1], value: parseFloat(m[2]), unit: m[3], date: m[4], isNew: true });
  }
  if (items.length > 0) {
    const rdMatch = txt.match(/"reportDate"\s*:\s*"([^"]+)"/);
    return {
      reportDate: rdMatch ? rdMatch[1] : new Date().toISOString().split('T')[0],
      summary: `Recovered ${items.length} items from partial response`,
      extracted: items
    };
  }

  return null;
}

// ── Main ──────────────────────────────────────────────────────────────────────
const rawText = extractRawText(aiInput);
let parsed    = safeParseAI(rawText);

if (!parsed) {
  parsed = {
    reportDate: new Date().toISOString().split('T')[0],
    summary:    'AI response could not be parsed. Raw: ' + String(rawText).substring(0, 300),
    extracted:  []
  };
}

const extracted = Array.isArray(parsed.extracted) ? parsed.extracted : [];

// ── Build FHIR category ───────────────────────────────────────────────────────
const catCode   = reportType === 'vitals' ? 'vital-signs' : 'laboratory';
const catSystem = 'http://terminology.hl7.org/CodeSystem/observation-category';

// ── Build FHIR Observation resources ─────────────────────────────────────────
const resources = extracted
  .filter(item => typeof item.value === 'number' && !isNaN(item.value))
  .map(item => ({
    resourceType: 'Observation',
    status: 'final',
    category: [{ coding: [{ system: catSystem, code: catCode, display: catCode }] }],
    code: { text: item.name, coding: [{ display: item.name }] },
    subject: { reference: 'Patient/' + patientId },
    effectiveDateTime: (item.date || parsed.reportDate) + 'T00:00:00Z',
    valueQuantity: { value: item.value, unit: item.unit || '' }
  }));

return [{ json: {
  reportDate: parsed.reportDate,
  summary:    parsed.summary,
  extracted,
  resources,
  patientId,
  fhirBase
} }];

// ─── PDF REPORT UPLOAD — Post ALL resources to FHIR ──────────────────────────
const prev      = $('PR: Build FHIR Resources').first().json;
const resources = prev.resources || [];
const fhirBase  = (prev.fhirBase || 'http://r4:8080/hapi-fhir-jpaserver/fhir').replace(/\/$/, '');

if (resources.length === 0) {
  return [{ json: { posted: 0, failed: 0, results: [], message: 'No resources to post' } }];
}

const results = [];

for (const resource of resources) {
  const url = `${fhirBase}/${resource.resourceType}`;
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        'Content-Type': 'application/fhir+json',
        'Accept': 'application/fhir+json'
      },
      body: resource,
      json: true,
      returnFullResponse: true,
    });

    results.push({
      name:   resource.code?.text || '?',
      status: response.statusCode,
      ok:     response.statusCode >= 200 && response.statusCode < 300,
      id:     response.body?.id || null
    });
  } catch (err) {
    results.push({
      name:   resource.code?.text || '?',
      status: err.response?.statusCode || 0,
      ok:     false,
      error:  err.message
    });
  }
}

const posted = results.filter(r => r.ok).length;
const failed = results.filter(r => !r.ok).length;

return [{ json: {
  posted,
  failed,
  results,
  message: `${posted} of ${resources.length} observations posted to FHIR`
} }];

// ─── PDF REPORT — Combine final response ─────────────────────────────────────
const built  = $('PR: Build FHIR Resources').first().json;
const posted = $('PR: Post to FHIR').first().json;

return [{ json: {
  reportDate:  built.reportDate,
  summary:     built.summary + ' — ' + posted.message,
  extracted:   built.extracted,
  resources:   built.resources,
  postResults: posted.results,
  posted:      posted.posted,
  failed:      posted.failed
} }];

// ─── CLINICAL NOTES — Extract transcript ─────────────────────────────────────
const body = $input.first().json.body || $input.first().json;
const patientId   = body.patientId   || '';
const patientName = body.patientName || 'Unknown';
const fhirBase    = body.fhirBase    || 'http://r4:8080/hapi-fhir-jpaserver/fhir';
const transcript  = body.transcript  || '';
const rawTranscript = Array.isArray(body.rawTranscript) ? body.rawTranscript : [];

if (!transcript && rawTranscript.length === 0) {
  throw new Error('transcript or rawTranscript is required');
}

// Build readable transcript from rawTranscript if plain text not provided
const text = transcript || rawTranscript.map(t => `[${t.time || ''}] ${t.speaker}: ${t.text}`).join('\n');

return [{ json: { patientId, patientName, fhirBase, transcript: text } }];

// ─── CLINICAL NOTES — Format & return HTML ─────────────────────────────────
const aiInput = $input.first().json;

function extractRawText(inp) {
  if (Array.isArray(inp.output)) {
    for (const msg of inp.output) {
      if (Array.isArray(msg.content)) {
        for (const block of msg.content) { if (block.text) return block.text; }
      }
      if (typeof msg.text === 'string') return msg.text;
    }
  }
  if (inp.message?.content)                                  return inp.message.content;
  if (Array.isArray(inp.choices) && inp.choices[0]?.message?.content)
                                                             return inp.choices[0].message.content;
  if (typeof inp.text    === 'string') return inp.text;
  if (typeof inp.content === 'string') return inp.content;
  if (typeof inp.output  === 'string') return inp.output;
  return JSON.stringify(inp);
}

let html = '';
try {
  html = extractRawText(aiInput).replace(/```html|```/g,'').trim();
} catch(e) { html = '<p>Error generating clinical notes: ' + e.message + '</p>'; }

if (!html) {
  html = '<p style="color:#991b1b">AI returned no content. Check OpenAI credentials and ensure the n8n OpenAI node has a valid API key configured.</p>';
}

const styledHtml = `<div style="font-family:system-ui,sans-serif;line-height:1.7;font-size:13px">
  <div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:10px 14px;margin-bottom:14px;color:#1e40af;font-size:12px">
    📋 AI-generated SOAP note — review before saving to chart
  </div>
  <div style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:16px">
    ${html}
  </div>
</div>`;

return [{ json: { html: styledHtml } }];

// ─── CHART UPDATES — Extract transcript ──────────────────────────────────────
const body = $input.first().json.body || $input.first().json;
const patientId   = body.patientId   || '';
const patientName = body.patientName || 'Unknown';
const fhirBase    = body.fhirBase    || 'http://r4:8080/hapi-fhir-jpaserver/fhir';
const transcript  = body.transcript  || '';
const rawTranscript = Array.isArray(body.rawTranscript) ? body.rawTranscript : [];
const text = transcript || rawTranscript.map(t => `[${t.time || ''}] ${t.speaker}: ${t.text}`).join('\n');

if (!text) throw new Error('transcript or rawTranscript is required');
return [{ json: { patientId, patientName, fhirBase, transcript: text } }];

