// ─── CHART UPDATES — Build FHIR resources + HTML summary ────────────────────
const aiInput   = $input.first().json;
const prev      = $('CU: Prepare Transcript').first().json;
const patientId = prev.patientId;

function extractRawText(inp) {
  if (Array.isArray(inp.output)) {
    for (const msg of inp.output) {
      if (Array.isArray(msg.content)) {
        for (const block of msg.content) { if (block.text) return block.text; }
      }
      if (typeof msg.text === 'string') return msg.text;
    }
  }
  if (inp.message?.content)                                  return inp.message.content;
  if (Array.isArray(inp.choices) && inp.choices[0]?.message?.content)
                                                             return inp.choices[0].message.content;
  if (typeof inp.text    === 'string') return inp.text;
  if (typeof inp.content === 'string') return inp.content;
  if (typeof inp.output  === 'string') return inp.output;
  return JSON.stringify(inp);
}

let parsed = { summary: '', resources: [] };
try {
  const rawText = extractRawText(aiInput);
  const clean = rawText.replace(/```json|```/g,'').trim();
  // Extract between first { and last } for robustness
  const s = clean.indexOf('{'), e = clean.lastIndexOf('}');
  const jsonStr = (s !== -1 && e > s) ? clean.substring(s, e + 1) : clean;
  parsed = JSON.parse(jsonStr);
} catch(e) {
  parsed.summary = 'Could not parse AI response: ' + e.message;
}

const resources = (parsed.resources || []).map(r => {
  if (r.subject?.reference === 'Patient/PATIENT_ID') {
    r.subject.reference = 'Patient/' + patientId;
  }
  return r;
});

const typeColors = {
  Condition: '#2563eb', MedicationRequest: '#7c3aed',
  Observation: '#0891b2', AllergyIntolerance: '#dc2626'
};
const typeIcons = {
  Condition: '🩺', MedicationRequest: '💊',
  Observation: '📊', AllergyIntolerance: '⚠️'
};

const rows = resources.map(r => {
  const rt    = r.resourceType || 'Unknown';
  const name  = r.code?.text || r.medicationCodeableConcept?.text || '—';
  const color = typeColors[rt] || '#6b7280';
  const icon  = typeIcons[rt]  || '📋';
  return `<div style="display:flex;align-items:center;gap:10px;padding:7px 10px;border-bottom:1px solid #f0f0f0">
    <span style="font-size:16px">${icon}</span>
    <span style="font-weight:500;font-size:13px">${name}</span>
    <span style="margin-left:auto;background:${color}20;color:${color};border:1px solid ${color}40;border-radius:4px;padding:1px 7px;font-size:11px;font-weight:600">${rt}</span>
  </div>`;
}).join('');

const html = `<div style="font-family:system-ui,sans-serif">
  <div style="background:#fefce8;border:1px solid #fde047;border-radius:8px;padding:10px 14px;margin-bottom:14px;color:#854d0e;font-size:12px">
    ⚠️ Proposed chart updates — review carefully before saving to FHIR
  </div>
  <div style="margin-bottom:12px;font-size:13px;color:#374151">${parsed.summary || 'No summary generated.'}</div>
  ${resources.length > 0 ? `<div style="border:1px solid #e5e7eb;border-radius:8px;overflow:hidden">${rows}</div>` : '<p style="color:#9ca3af;font-size:13px">No chart updates extracted.</p>'}
</div>`;

return [{ json: { html, resources, summary: parsed.summary } }];

// ─── VIRTUAL DOCTOR — Prepare context ────────────────────────────────────────
const body        = $input.first().json.body || $input.first().json;
const patientId   = body.patientId   || '';
const patientName = body.patientName || 'Unknown';
const fhirBase    = body.fhirBase    || '';
const patientInput = body.patientInput || '';
const transcript  = body.transcript  || '';
const today       = body.today       || new Date().toISOString().split('T')[0];

// Count how many AI turns have happened (to know when to wrap up)
const rawTranscript = body.rawTranscript || [];
const aiTurns = rawTranscript.filter(e => e.speaker === 'ai-doctor').length;

return [{
  json: {
    patientId,
    patientName,
    fhirBase,
    patientInput,
    transcript,
    rawTranscript,
    aiTurns,
    today,
    isStart: patientInput === 'START_CONSULTATION',
  }
}];

// ─── VIRTUAL DOCTOR — Parse AI reply & return ──────────────────────────────
const aiInput = $input.first().json;
let reply = 'I\'m sorry, I didn\'t get that. Could you repeat your symptoms?';
let done  = false;

function extractRawText(inp) {
  if (Array.isArray(inp.output)) {
    for (const msg of inp.output) {
      if (Array.isArray(msg.content)) {
        for (const block of msg.content) { if (block.text) return block.text; }
      }
      if (typeof msg.text === 'string') return msg.text;
    }
  }
  if (inp.message?.content)                                  return inp.message.content;
  if (Array.isArray(inp.choices) && inp.choices[0]?.message?.content)
                                                             return inp.choices[0].message.content;
  if (typeof inp.text    === 'string') return inp.text;
  if (typeof inp.content === 'string') return inp.content;
  if (typeof inp.output  === 'string') return inp.output;
  return JSON.stringify(inp);
}

try {
  const raw = extractRawText(aiInput);
  const clean = raw.replace(/```json|```/g, '').trim();
  try {
    const parsed = JSON.parse(clean);
    reply = parsed.reply || reply;
    done  = parsed.done === true;
  } catch {
    reply = clean.replace('[CONSULTATION_COMPLETE]', '').trim();
    done  = clean.includes('[CONSULTATION_COMPLETE]');
  }
} catch(e) {
  reply = 'Sorry, something went wrong. Please try again.';
}

return [{ json: { reply, done } }];

// ── PPH RISK SCORER ─────────────────────────────────────────────────────────
const input     = $input.first().json ?? {};
const patientId = input.patientId ?? '';
const fhirBase  = (input.fhirBase ?? '').replace('localhost', 'host.docker.internal');

// Fetch patient directly from FHIR to get extensions
const patient = await this.helpers.request({
  method: 'GET',
  url: `${fhirBase}/Patient/${patientId}`,
  json: true,
});

// Build extension map
const extMap = {};
for (const e of (patient.extension ?? [])) {
  const key = e.url?.split('/').pop();
  extMap[key] = e.valueBoolean ?? e.valueString ?? e.valueInteger ?? e.valueDecimal ?? null;
}

const isPPHPatient = extMap['pph-data'] === true;
if (!isPPHPatient) {
  const html = `<div style="font-family:system-ui,sans-serif;padding:20px">
  <div style="background:#fefce8;border:2px solid #ca8a04;border-radius:10px;padding:20px;display:flex;gap:16px">
    <div style="font-size:32px">⚠️</div>
    <div>
      <div style="font-weight:700;font-size:16px;color:#92400e;margin-bottom:6px">PPH Risk Scorer — Not Applicable</div>
      <div style="color:#78350f;font-size:13px;line-height:1.6">
        This patient does not have PPH study data.<br>
        Select a patient with ID starting with <code>pph-</code>.
      </div>
    </div>
  </div>
</div>`;
  return [{ json: { html } }];
}

const INTERCEPT = 1.841479546675375;
const COEF = {
  prior_pph: 2.066763894920142, placenta_accreta: 0.7182751426644561,
  general_anesthesia: -1.240939494699953, multiple_gestation: 0.41106791473747695,
  placenta_previa: 0.5840560162568934, induction_of_labor: 0.5777167703423556,
  augmentation: 0.3770777905429483, labor_length: -0.31600619533829494,
  maternal_obesity: 0.12286688448471364, cesarean_prior: 0.0532285503233866,
  hypertensive_disorder: 0.1943587276475948, diabetes: -0.3172832269160743,
  chorioamnionitis: 0.7771971213880927, polyhydramnios: 0.18064912929107257,
  fetal_macrosomia: 0.2275318678827409, hematocrit: -0.06105462012649221,
  platelet: -0.0033577033137540003, maternal_weight: 0.0011523405822029705,
  pulse: 0.011021216678819435, wbc: 0.0023955871122740688,
};
const DELIVERY_COEF = {
  'Cesarean': 0.0, 'Instrumented vaginal': -0.7087293734514933, 'Vaginal': -0.9568864148746021,
};
const MEDIANS = {
  hematocrit: 35.49, platelet: 229.35, maternal_weight: 82.07, pulse: 88.23, wbc: 11.04,
};
const Q1 = 0.34344335186935243;
const Q2 = 0.5039517715029438;
const sigmoid = z => 1 / (1 + Math.exp(-z));

// Read binary features from extensions
const delivery    = extMap['delivery-type']         ?? 'Cesarean';
const prior_pph   = extMap['prior-pph']             ?? 0;
const pl_accreta  = extMap['placenta-accreta']      ?? 0;
const gen_anes    = extMap['general-anesthesia']    ?? 0;
const mult_gest   = extMap['multiple-gestation']    ?? 0;
const pl_previa   = extMap['placenta-previa']       ?? 0;
const induction   = extMap['induction-of-labor']    ?? 0;
const augment     = extMap['augmentation']          ?? 0;
const labor_len   = extMap['labor-length']          ?? 0;
const mat_obesity = extMap['maternal-obesity']      ?? 0;
const ces_prior   = extMap['cesarean-prior']        ?? 0;
const htn         = extMap['hypertensive-disorder'] ?? 0;
const diabetes    = extMap['diabetes']              ?? 0;
const chorioamn   = extMap['chorioamnionitis']      ?? 0;
const polyhydr    = extMap['polyhydramnios']        ?? 0;
const fet_macro   = extMap['fetal-macrosomia']      ?? 0;
const pphOutcome  = extMap['pph-outcome'];
const valLabel    = extMap['validation-label']      ?? '—';
const storedProb  = extMap['model-pph-prob'];

// Continuous features from merged observations or medians
const hematocrit = input.hematocrit      != null ? Number(input.hematocrit)      : MEDIANS.hematocrit;
const platelet   = input.platelet        != null ? Number(input.platelet)        : MEDIANS.platelet;
const mat_weight = input.maternal_weight != null ? Number(input.maternal_weight) : MEDIANS.maternal_weight;
const pulse      = input.pulse           != null ? Number(input.pulse)           : MEDIANS.pulse;
const wbc        = input.wbc             != null ? Number(input.wbc)             : MEDIANS.wbc;

// Compute score
let z = INTERCEPT;
z += COEF.prior_pph             * Number(prior_pph);
z += COEF.placenta_accreta      * Number(pl_accreta);
z += COEF.general_anesthesia    * Number(gen_anes);
z += COEF.multiple_gestation    * Number(mult_gest);
z += COEF.placenta_previa       * Number(pl_previa);
z += COEF.induction_of_labor    * Number(induction);
z += COEF.augmentation          * Number(augment);
z += COEF.labor_length          * Number(labor_len);
z += COEF.maternal_obesity      * Number(mat_obesity);
z += COEF.cesarean_prior        * Number(ces_prior);
z += COEF.hypertensive_disorder * Number(htn);
z += COEF.diabetes              * Number(diabetes);
z += COEF.chorioamnionitis      * Number(chorioamn);
z += COEF.polyhydramnios        * Number(polyhydr);
z += COEF.fetal_macrosomia      * Number(fet_macro);
z += COEF.hematocrit            * hematocrit;
z += COEF.platelet              * platelet;
z += COEF.maternal_weight       * mat_weight;
z += COEF.pulse                 * pulse;
z += COEF.wbc                   * wbc;
z += (DELIVERY_COEF[delivery]   ?? 0);

const prob      = sigmoid(z);
const probPct   = (prob * 100).toFixed(1);
const riskTier  = prob <= Q1 ? 'Low' : prob <= Q2 ? 'Medium' : 'High';
const tierColor = { Low:'#16a34a', Medium:'#ca8a04', High:'#dc2626' }[riskTier];
const tierBg    = { Low:'#f0fdf4', Medium:'#fefce8', High:'#fef2f2' }[riskTier];
const tierIcon  = { Low:'🟢', Medium:'🟡', High:'🔴' }[riskTier];
const outcomeColor = pphOutcome === 1 ? '#dc2626' : '#16a34a';
const outcomeBg    = pphOutcome === 1 ? '#fef2f2' : '#f0fdf4';
const outcomeText  = pphOutcome === 1 ? '🔴 PPH Occurred' : '🟢 No PPH';

const features = [
  { label:'Prior PPH',             val:Number(prior_pph),   coef:COEF.prior_pph,             type:'b' },
  { label:'Chorioamnionitis',      val:Number(chorioamn),   coef:COEF.chorioamnionitis,       type:'b' },
  { label:'Placenta Accreta',      val:Number(pl_accreta),  coef:COEF.placenta_accreta,       type:'b' },
  { label:'Placenta Previa',       val:Number(pl_previa),   coef:COEF.placenta_previa,        type:'b' },
  { label:'Induction of Labor',    val:Number(induction),   coef:COEF.induction_of_labor,     type:'b' },
  { label:'Multiple Gestation',    val:Number(mult_gest),   coef:COEF.multiple_gestation,     type:'b' },
  { label:'Augmentation',          val:Number(augment),     coef:COEF.augmentation,           type:'b' },
  { label:'Fetal Macrosomia',      val:Number(fet_macro),   coef:COEF.fetal_macrosomia,       type:'b' },
  { label:'Polyhydramnios',        val:Number(polyhydr),    coef:COEF.polyhydramnios,         type:'b' },
  { label:'Maternal Obesity',      val:Number(mat_obesity), coef:COEF.maternal_obesity,       type:'b' },
  { label:'Hypertensive Disorder', val:Number(htn),         coef:COEF.hypertensive_disorder,  type:'b' },
  { label:'General Anesthesia',    val:Number(gen_anes),    coef:COEF.general_anesthesia,     type:'b' },
  { label:'Diabetes',              val:Number(diabetes),    coef:COEF.diabetes,               type:'b' },
  { label:'Long Labor',            val:Number(labor_len),   coef:COEF.labor_length,           type:'b' },
  { label:'Prior Cesarean',        val:Number(ces_prior),   coef:COEF.cesarean_prior,         type:'b' },
  { label:`Hematocrit (${hematocrit.toFixed(1)}%)`,    val:hematocrit,  coef:COEF.hematocrit,      type:'c', ref:MEDIANS.hematocrit },
  { label:`Platelet (${platelet.toFixed(0)} K/µL)`,    val:platelet,    coef:COEF.platelet,        type:'c', ref:MEDIANS.platelet },
  { label:`Weight (${mat_weight.toFixed(1)} kg)`,      val:mat_weight,  coef:COEF.maternal_weight, type:'c', ref:MEDIANS.maternal_weight },
  { label:`Pulse (${pulse.toFixed(0)} bpm)`,           val:pulse,       coef:COEF.pulse,           type:'c', ref:MEDIANS.pulse },
  { label:`WBC (${wbc.toFixed(1)} K/µL)`,              val:wbc,         coef:COEF.wbc,             type:'c', ref:MEDIANS.wbc },
];

const rows = features.map(f => {
  const contrib = f.type === 'b' ? f.coef * f.val : f.coef * (f.val - f.ref);
  const dispVal = f.type === 'b' ? (f.val ? 'Yes' : 'No') : f.label.match(/\(([^)]+)\)/)?.[1] ?? f.val.toFixed(2);
  const lbl     = f.type === 'c' ? f.label.split(' (')[0] : f.label;
  const barW    = Math.min(100, Math.abs(contrib) * 60).toFixed(0);
  const dir     = contrib > 0 ? '#dc2626' : contrib < 0 ? '#16a34a' : '#9ca3af';
  const sign    = contrib > 0 ? '▲' : contrib < 0 ? '▼' : '—';
  const opacity = f.type === 'b' && f.val === 0 ? '0.38' : '1';
  return `<tr style="border-bottom:1px solid #f3f4f6;opacity:${opacity}">
    <td style="padding:5px 10px;font-size:13px">${lbl}</td>
    <td style="padding:5px 10px;text-align:center;font-size:12px;color:${f.type==='b'&&f.val?'#4f46e5':'#6b7280'}">${dispVal}</td>
    <td style="padding:5px 10px"><div style="display:flex;align-items:center;gap:6px">
      <div style="width:70px;background:#f3f4f6;border-radius:3px;height:7px;flex-shrink:0">
        <div style="width:${barW}%;background:${dir};height:7px;border-radius:3px"></div>
      </div>
      <span style="font-size:11px;color:${dir};font-weight:700">${sign} ${contrib.toFixed(3)}</span>
    </div></td>
  </tr>`;
}).join('');

const html = `
<div style="font-family:system-ui,sans-serif">
  <div style="background:${tierBg};border:2px solid ${tierColor};border-radius:12px;padding:18px 22px;margin-bottom:16px;display:flex;align-items:center;gap:18px">
    <div style="font-size:44px">${tierIcon}</div>
    <div style="flex:1">
      <div style="font-size:26px;font-weight:800;color:${tierColor}">${riskTier} Risk</div>
      <div style="font-size:16px;font-weight:600;color:${tierColor};margin-top:2px">${probPct}% predicted PPH probability</div>
      ${storedProb != null ? `<div style="font-size:12px;color:#6b7280;margin-top:4px">Pre-computed (stored): <strong>${(storedProb*100).toFixed(1)}%</strong></div>` : ''}
      <div style="font-size:11px;color:#6b7280;margin-top:6px">AUC 0.75 · Low ≤${(Q1*100).toFixed(1)}% · Med ≤${(Q2*100).toFixed(1)}% · High >${(Q2*100).toFixed(1)}%</div>
    </div>
    <div style="text-align:center;background:#fff;border-radius:8px;padding:10px 14px;border:1px solid #e5e7eb">
      <div style="font-size:28px;font-weight:800;color:${tierColor}">${probPct}%</div>
      <div style="font-size:11px;color:#6b7280">PPH Prob</div>
    </div>
  </div>

  <div style="background:${outcomeBg};border:1px solid ${outcomeColor}40;border-radius:8px;padding:12px 16px;margin-bottom:16px;display:flex;justify-content:space-between;align-items:center">
    <div>
      <div style="font-weight:700;font-size:13px;color:${outcomeColor}">Actual Study Outcome</div>
      <div style="font-size:12px;color:#6b7280;margin-top:2px">${valLabel} cohort</div>
    </div>
    <div style="font-size:15px;font-weight:700;color:${outcomeColor}">${outcomeText}</div>
  </div>

  <div style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:14px;margin-bottom:14px">
    <div style="font-weight:700;font-size:13px;margin-bottom:10px">Clinical Features</div>
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;font-size:12px">
      <div><span style="color:#6b7280">Delivery:</span> <strong>${delivery}</strong></div>
      <div><span style="color:#6b7280">Hematocrit:</span> <strong>${hematocrit.toFixed(1)}%</strong></div>
      <div><span style="color:#6b7280">Platelet:</span> <strong>${platelet.toFixed(0)} K/µL</strong></div>
      <div><span style="color:#6b7280">Pulse:</span> <strong>${pulse.toFixed(0)} bpm</strong></div>
      <div><span style="color:#6b7280">Weight:</span> <strong>${mat_weight.toFixed(1)} kg</strong></div>
      <div><span style="color:#6b7280">WBC:</span> <strong>${wbc.toFixed(1)} K/µL</strong></div>
    </div>
  </div>

  <div style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:14px">
    <div style="font-weight:700;font-size:13px;margin-bottom:10px">Feature Contributions</div>
    <table style="width:100%;border-collapse:collapse">
      <thead><tr style="background:#f9fafb">
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280">FEATURE</th>
        <th style="padding:7px 10px;text-align:center;font-size:11px;color:#6b7280">VALUE</th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#6b7280">CONTRIBUTION</th>
      </tr></thead>
      <tbody>
        <tr style="border-bottom:1px solid #f3f4f6">
          <td style="padding:5px 10px;font-size:13px">Delivery Type</td>
          <td style="padding:5px 10px;text-align:center;font-size:12px;color:#4f46e5">${delivery}</td>
          <td style="padding:5px 10px;font-size:11px;color:#6b7280">${(DELIVERY_COEF[delivery]??0).toFixed(3)}</td>
        </tr>
        ${rows}
      </tbody>
    </table>
  </div>
  <div style="font-size:11px;color:#9ca3af;margin-top:8px">⚠ Educational use only · model.pkl schema · Grayed = risk factor absent</div>
</div>`;

return [{ json: { html } }];

// Merge FHIR Observation values into the payload for continuous features

// Input from Fetch Observations is a raw JSON string in .data field — parse it
const raw = $input.first().json;
let obs_bundle = {};
if (raw.data && typeof raw.data === 'string') {
  try { obs_bundle = JSON.parse(raw.data); } catch(e) { obs_bundle = {}; }
} else {
  obs_bundle = raw;
}

const entries = obs_bundle.entry?.map(e => e.resource) ?? [];

// Get original webhook payload (patientId, patientData, fhirBase)
const webhookNode = $('POST /pph-risk-run').first().json;
const webhookData = webhookNode?.body ?? webhookNode ?? {};

const latest = {};
for (const obs of entries) {
  const code = obs.code?.coding?.[0]?.code;
  const val  = obs.valueQuantity?.value;
  const dt   = new Date(obs.effectiveDateTime || obs.issued || 0);
  if (code && val != null) {
    if (!latest[code] || dt > new Date(latest[code].dt)) {
      latest[code] = { val, dt: obs.effectiveDateTime || obs.issued };
    }
  }
}

// LOINC → feature name mapping
const loincMap = {
  '20570-8': 'hematocrit',
  '777-3':   'platelet',
  '26449-9': 'platelet',
  '32623-1': 'platelet',
  '29463-7': 'maternal_weight',
  '8867-4':  'pulse',
  '26464-8': 'wbc',
};

const merged = { ...webhookData };
for (const [loinc, feature] of Object.entries(loincMap)) {
  if (latest[loinc] != null) merged[feature] = latest[loinc].val;
}

return [{ json: merged }];
